1	package fan.summer.ui;
2	
3	import fan.summer.plugin.PluginLoader;
4	import fan.summer.plugin.PluginRegistry;
5	import fan.summer.ui.content.ContentArea;
6	import fan.summer.ui.setting.SwissKitJSettingUi;
7	import fan.summer.ui.sidebar.Sidebar;
8	import fan.summer.ui.titlebar.TitleBar;
9	import fan.summer.api.SwissKitJPlugin;
10	import javafx.animation.*;
11	import javafx.geometry.Insets;
12	import javafx.geometry.Pos;
13	import javafx.scene.control.Label;
14	import javafx.scene.layout.*;
15	import javafx.scene.paint.Color;
16	import javafx.scene.shape.Circle;
17	import javafx.scene.shape.Rectangle;
18	import javafx.stage.Stage;
19	import javafx.util.Duration;
20	import org.slf4j.Logger;
21	import org.slf4j.LoggerFactory;
22	
23	import java.time.LocalTime;
24	import java.time.format.DateTimeFormatter;
25	
26	/**
27	 * Root node of the main window.
28	 * Assembles TitleBar / Sidebar / ContentArea / StatusBar,
29	 * and holds the lifecycle for PluginLoader and PluginRegistry.
30	 */
31	public class MainWindow extends StackPane {
32	
33	    private static final Logger log = LoggerFactory.getLogger(MainWindow.class);
34	
35	    private final Stage        stage;
36	    private final PluginLoader loader;
37	    private final PluginRegistry registry;
38	
39	    private final TitleBar    titleBar;
40	    private final Sidebar     sidebar;
41	    private final ContentArea contentArea;
42	
43	    // Status bar labels
44	    private Label statusToolCount    = statusText("0 tools");
45	    private Label statusPluginCount  = statusText("0 plugins");
46	    private final Label clockLabel         = statusText("");
47	
48	    private Timeline clockTimeline;
49	
50	    public MainWindow(Stage stage, PluginLoader loader, PluginRegistry registry) {
51	        log.debug("Initialising MainWindow");
52	        this.stage    = stage;
53	        this.loader   = loader;
54	        this.registry = registry;
55	
56	        titleBar    = new TitleBar(stage, this::openSettings);
57	        sidebar     = new Sidebar();
58	        contentArea = new ContentArea();
59	
60	        int buildInTool = 0;
61	        int pluginInTool = 0;
62	        for (SwissKitJPlugin plugin : registry.getPlugins()) {
63	            if(plugin.getType().equals("plugin") ) {
64	                pluginInTool++;
65	            }else {
66	                buildInTool++;
67	            }
68	        }
69	
70	        statusPluginCount = statusText(pluginInTool + "plugins");
71	        statusToolCount = statusText(pluginInTool + buildInTool +  "tools");
72	
73	        buildScene();
74	        wireEvents();
75	        startClock();
76	        playEntryAnimation();
77	    }
78	
79	    // ── Build scene graph ────────────────────────────────
80	
81	    private void buildScene() {
82	        // Background orb layer (bottom layer)
83	        Pane orbLayer = buildOrbLayer();
84	
85	        // Main window glass panel
86	        BorderPane windowPane = new BorderPane();
87	        windowPane.getStyleClass().add("app-root");
88	        windowPane.setStyle(
89	            "-fx-background-color: rgba(13,14,17,0.72);" +
90	            "-fx-background-radius: 20;" +
91	            "-fx-border-radius: 20;" +
92	            "-fx-border-color: rgba(255,255,255,0.10);" +
93	            "-fx-border-width: 1;" +
94	            "-fx-effect: dropshadow(gaussian, rgba(0,0,0,0.6), 60, 0, 0, 20);"
95	        );
96	
97	        // Title bar
98	        windowPane.setTop(titleBar);
99	
100	        // Body: sidebar + content area
101	        HBox body = new HBox(sidebar, contentArea);
102	        HBox.setHgrow(contentArea, Priority.ALWAYS);
103	        windowPane.setCenter(body);
104	
105	        // Status bar
106	        windowPane.setBottom(buildStatusBar());
107	
108	        // Top highlight border (glass thickness simulation)
109	        Rectangle topHighlight = new Rectangle();
110	        topHighlight.setMouseTransparent(true);
111	        topHighlight.setStyle(
112	            "-fx-fill: transparent;" +
113	            "-fx-stroke: rgba(255,255,255,0.12);" +
114	            "-fx-stroke-width: 1;" +
115	            "-fx-arc-width: 40; -fx-arc-height: 40;"
116	        );
117	        topHighlight.widthProperty().bind(widthProperty());
118	        topHighlight.heightProperty().bind(heightProperty());
119	
120	        getChildren().addAll(orbLayer, windowPane, topHighlight);
121	        setAlignment(windowPane, Pos.CENTER);
122	        setAlignment(topHighlight, Pos.CENTER);
123	    }
124	
125	    // ── Background orbs ───────────────────────────────────
126	
127	    private Pane buildOrbLayer() {
128	        Pane layer = new Pane();
129	        layer.setMouseTransparent(true);
130	        layer.setStyle("-fx-background-color: #0d0e11;");
131	
132	        // Three colored Gaussian blur orbs
133	        layer.getChildren().addAll(
134	            orb(480, "#3b5bdb", -80, -120, 0),
135	            orb(360, "#7048e8",  -60, 200,  -6000),
136	            orb(300, "#1c7ed6",  300, 400, -12000)
137	        );
138	        return layer;
139	    }
140	
141	    private StackPane orb(double size, String color, double x, double y, double animDelay) {
142	        Circle c = new Circle(size / 2,
143	            Color.web(color, 0.28));
144	        c.setEffect(new javafx.scene.effect.GaussianBlur(60));
145	
146	        StackPane wrap = new StackPane(c);
147	        wrap.setTranslateX(x);
148	        wrap.setTranslateY(y);
149	        wrap.setMouseTransparent(true);
150	
151	        // Floating animation
152	        TranslateTransition drift = new TranslateTransition(Duration.millis(18000), wrap);
153	        drift.setByX(30); drift.setByY(20);
154	        drift.setAutoReverse(true);
155	        drift.setCycleCount(Animation.INDEFINITE);
156	        drift.setDelay(Duration.millis(Math.abs(animDelay)));
157	        drift.setInterpolator(Interpolator.EASE_BOTH);
158	        drift.play();
159	
160	        ScaleTransition breathe = new ScaleTransition(Duration.millis(12000), wrap);
161	        breathe.setFromX(1.0); breathe.setFromY(1.0);
162	        breathe.setToX(1.08);  breathe.setToY(1.08);
163	        breathe.setAutoReverse(true);
164	        breathe.setCycleCount(Animation.INDEFINITE);
165	        breathe.setInterpolator(Interpolator.EASE_BOTH);
166	        breathe.play();
167	
168	        return wrap;
169	    }
170	
171	    // ── Status bar ───────────────────────────────────────
172	
173	    private HBox buildStatusBar() {
174	        // Activity indicator dot
