204	    private void wireEvents() {
205	        // Bind plugin list to content area
206	        contentArea.setPlugins(registry.getPlugins());
207	
208	        // Sidebar category switch → content area filter
209	        sidebar.setOnCategorySelect(categoryId -> {
210	            if ("store".equals(categoryId)) {
211	                contentArea.showPage(fan.summer.ui.store.PluginStoreUi.build(), "Plugin Store");
212	            } else if ("settings".equals(categoryId)) {
213	                // settings is handled by setOnSettingsSelect
214	            } else {
215	                contentArea.showCategory(categoryId);
216	            }
217	        });
218	
219	        // Settings (standalone, not part of nav state machine)
220	        sidebar.setOnSettingsSelect(this::openSettings);
221	
222	        // Plugin list change → update status bar
223	        registry.getPlugins().addListener(
224	            (javafx.collections.ListChangeListener<SwissKitJPlugin>) c -> {
225	                int total   = registry.getPlugins().size();
226	                int plugins = (int) registry.getPlugins().stream()
227	                    .filter(p -> !"builtin".equals(p.getType())).count();
228	                statusToolCount.setText(total + " tools");
229	                statusPluginCount.setText(plugins + " plugins");
230	                sidebar.updateBadge("plugins", plugins);
231	            }
232	        );
233	
234	        // Tool launch callback
235	        contentArea.setOnLaunch(plugin -> {
236	            log.info("Launching tool: id={}, name={}", plugin.getId(), plugin.getName());
237	            registry.activate(plugin);
238	            try {
239	                contentArea.showPage(plugin.createView(), plugin.getName());
240	            } catch (Exception e) {
241	                log.error("Failed to create view for plugin {}: {}", plugin.getId(), e.getMessage(), e);
242	            }
243	        });
244	
245	        // Back / exit plugin view callback
246	        contentArea.setOnBack(() -> {
247	            log.debug("Returning to home from active plugin");
248	            registry.deactivate();
249	        });
250	    }
