266	        windowPane.setScaleX(0.94);
267	        windowPane.setScaleY(0.94);
268	        windowPane.setTranslateY(16);
269	
270	        FadeTransition ft = new FadeTransition(Duration.millis(500), windowPane);
271	        ft.setToValue(1);
272	
273	        ScaleTransition st = new ScaleTransition(Duration.millis(500), windowPane);
274	        st.setToX(1); st.setToY(1);
