277	        TranslateTransition tt = new TranslateTransition(Duration.millis(500), windowPane);
278	        tt.setToY(0);
279	        tt.setInterpolator(Interpolator.SPLINE(0.34, 0.9, 0.64, 1.0));
280	
281	        new ParallelTransition(ft, st, tt).play();
282	    }
