319	    private static void saveEmailSettings(VBox form) {
320	        String smtp = null, port = null, user = null, pass = null, from = null;
321	        boolean tls = false, ssl = false;
322	        List<Node> children = form.getChildren();
323	
324	        for (Node child : children) {
325	            if (child instanceof HBox hb && hb.getChildren().size() >= 2) {
326	                Object first = hb.getChildren().get(0);
327	                if (first instanceof Label lbl) {
328	                    String text = lbl.getText();
329	                    Object field = hb.getChildren().get(1);
330	                    if ("SMTP Server".equals(text) && field instanceof TextField tf) smtp = tf.getText();
331	                    else if ("Port".equals(text) && field instanceof TextField tf) port = tf.getText();
332	                    else if ("Username".equals(text) && field instanceof TextField tf) user = tf.getText();
333	                    else if ("Password".equals(text) && field instanceof PasswordField pf) pass = pf.getText();
334	                    else if ("From Address".equals(text) && field instanceof TextField tf) from = tf.getText();
335	                }
336	            } else if (child instanceof VBox vb) {
337	                for (Node vbChild : vb.getChildren()) {
338	                    if (vbChild instanceof HBox hb && hb.getChildren().size() == 2) {
339	                        Object first = hb.getChildren().get(0);
340	                        Object second = hb.getChildren().get(1);
341	                        if (first instanceof CheckBox tlsCb && "TLS".equals(tlsCb.getText())) tls = tlsCb.isSelected();
342	                        if (second instanceof CheckBox sslCb && "SSL".equals(sslCb.getText())) ssl = sslCb.isSelected();
343	                    }
344	                }
345	            }
346	        }
347	
348	        if (smtp == null || smtp.isBlank() || port == null || port.isBlank()
349	                || user == null || user.isBlank() || pass == null || pass.isBlank()
350	                || from == null || from.isBlank()) {
351	            alert(Alert.AlertType.WARNING, "Validation Error", "All fields are required.");
352	            return;
353	        }
354	
355	        if (tls && ssl) {
356	            alert(Alert.AlertType.WARNING, "Validation Error", "TLS and SSL cannot be both selected.");
357	            return;
358	        }
359	
360	        final String fSmtp = smtp.trim();
361	        final String fPort = port.trim();
362	        final String fUser = user.trim();
363	        final String fPass = pass.trim();
364	        final String fFrom = from.trim();
365	        final boolean fTls = tls;
366	        final boolean fSsl = ssl;
367	
368	        new Thread(() -> {
369	            try (SqlSession session = DatabaseInit.getSqlSession()) {
370	                SwissKitSettingEmailMapper mapper = session.getMapper(SwissKitSettingEmailMapper.class);
371	                mapper.deleteAll();
372	                SwissKitSettingEmailEntity entity = new SwissKitSettingEmailEntity();
373	                entity.setSmtpAddress(fSmtp);
374	                entity.setSmtpPort(Integer.parseInt(fPort));
375	                entity.setEmail(fUser);
376	                entity.setPassword(fPass);
377	                entity.setFromAddress(fFrom);
378	                entity.setNeedTLS(fTls);
379	                entity.setNeedSSL(fSsl);
380	                mapper.insert(entity);
381	                session.commit();
382	                log.info("Email settings saved: smtp={}:{}", fSmtp, fPort);
383	                Platform.runLater(() -> {
384	                    Alert a = new Alert(Alert.AlertType.INFORMATION);
385	                    a.setTitle("Success");
386	                    a.setHeaderText(null);
387	                    a.setContentText("Email settings saved successfully.");
388	                    a.showAndWait();
389	                });
390	            } catch (Exception ex) {
391	                log.error("Failed to save email settings", ex);
392	                Platform.runLater(() -> alert(Alert.AlertType.ERROR, "Error", "Failed to save: " + ex.getMessage()));
393	            }
394	        }).start();
395	    }
