855	    private static void deployPlugin(File source) {
856	        new Thread(() -> {
857	            try {
858	                Path pluginDir = Path.of(System.getProperty("user.dir"), "plugins");
859	                Files.createDirectories(pluginDir);
860	                Path target = pluginDir.resolve(source.getName());
861	                Files.copy(source.toPath(), target, StandardCopyOption.REPLACE_EXISTING);
862	                log.info("Plugin deployed: {}", target);
863	                Platform.runLater(() -> {
864	                    pluginPathField.setText("");
865	                    refreshPluginList();
866	                    alert(Alert.AlertType.INFORMATION, "Success", "Plugin deployed: " + source.getName());
867	                });
868	            } catch (Exception ex) {
869	                log.error("Plugin deploy failed", ex);
870	                Platform.runLater(() -> alert(Alert.AlertType.ERROR, "Error", "Deploy failed: " + ex.getMessage()));
871	            }
872	        }).start();
873	    }
