221	    // ── Grid refresh ──────────────────────────────────────────
222	
223	    private void refresh() {
224	        if (plugins == null) return;
225	
226	        List<SwissKitJPlugin> filtered = plugins.stream()
227	            .filter(this::matchesCategory)
228	            .filter(this::matchesQuery)
229	            .toList();
230	
231	        toolGrid.getChildren().clear();
232	
233	        for (int i = 0; i < filtered.size(); i++) {
234	            SwissKitJPlugin p = filtered.get(i);
235	            ToolCard card = new ToolCard(p, this::onCardSelect);
236	            card.setPrefWidth(152);
237	            card.setPrefHeight(130);
238	
239	            // Staggered entry delay
240	            int delay = i * 35;
241	            card.setOpacity(0);
242	            PauseTransition pause = new PauseTransition(Duration.millis(delay));
243	            pause.setOnFinished(e -> {
244	                FadeTransition ft = new FadeTransition(Duration.millis(240), card);
245	                ft.setFromValue(0); ft.setToValue(1);
246	                TranslateTransition tt = new TranslateTransition(Duration.millis(240), card);
247	                tt.setFromY(10); tt.setToY(0);
248	                new ParallelTransition(ft, tt).play();
249	            });
250	            pause.play();
251	
252	            toolGrid.getChildren().add(card);
253	        }
254	
255	        // Empty state message
256	        if (filtered.isEmpty()) {
257	            Label empty = new Label("No matching tools found");
258	            empty.setStyle("-fx-text-fill: rgba(255,255,255,0.28); -fx-font-size: 13px;");
259	            empty.setPadding(new Insets(40, 0, 0, 0));
260	            toolGrid.getChildren().add(empty);
261	        }
262	    }
263	
264	    // ── Filter logic ──────────────────────────────────────────
265	
266	    private boolean matchesCategory(SwissKitJPlugin p) {
267	        return switch (currentCategory) {
268	            case "all"     -> true;
269	            case "plugins" -> !"builtin".equals(p.getType());
270	            case "fav"     -> false; // TODO: integrate favorites persistence
271	            default        -> p.getCategory().equalsIgnoreCase(currentCategory);
272	        };
273	    }
274	
275	    private boolean matchesQuery(SwissKitJPlugin p) {
276	        if (currentQuery.isEmpty()) return true;
277	        return p.getName().toLowerCase().contains(currentQuery)
278	            || p.getDescription().toLowerCase().contains(currentQuery);
279	    }
280	
281	    // ── Card selection ──────────────────────────────────────────
282	
283	    private void onCardSelect(SwissKitJPlugin plugin) {
284	        detailPanel.show(plugin);
285	    }
286	
287	    // ── Page transition animation (cross-fade) ──────────────────────
288	
289	    private void crossFadeTo(Node next) {
290	        Node current = pageStack.getChildren().isEmpty()
291	            ? null : pageStack.getChildren().get(0);
292	
293	        next.setOpacity(0);
294	        if (!pageStack.getChildren().contains(next))
295	            pageStack.getChildren().add(next);
296	        next.toFront();
297	
298	        FadeTransition fadeIn = new FadeTransition(Duration.millis(220), next);
299	        fadeIn.setToValue(1);
300	
301	        if (current != null && current != next) {
302	            FadeTransition fadeOut = new FadeTransition(Duration.millis(180), current);
303	            fadeOut.setToValue(0);
304	            Node finalCurrent = current;
305	            fadeOut.setOnFinished(e -> pageStack.getChildren().remove(finalCurrent));
306	            new ParallelTransition(fadeOut, fadeIn).play();
307	        } else {
308	            fadeIn.play();
309	        }
310	    }
311	
312	    private void animateGridIn() {
313	        // Grid slides in from slightly below
314	        TranslateTransition tt = new TranslateTransition(Duration.millis(280), toolGrid);
315	        tt.setFromY(12); tt.setToY(0);
316	        FadeTransition ft = new FadeTransition(Duration.millis(280), toolGrid);
317	        ft.setFromValue(0.4); ft.setToValue(1);
318	        new ParallelTransition(tt, ft).play();
319	    }
320	
