322	
323	    private HBox sectionHeader(String title, String action) {
324	        Label titleLabel = new Label(title.toUpperCase());
325	        titleLabel.getStyleClass().add("section-title");
326	
327	        Region spacer = new Region();
328	        HBox.setHgrow(spacer, Priority.ALWAYS);
329	
330	        HBox row = new HBox(titleLabel, spacer);
331	        if (!action.isEmpty()) {
332	            Label actionLabel = new Label(action);
333	            actionLabel.setStyle("-fx-text-fill: #5b8cf7; -fx-font-size: 12px; -fx-cursor: hand;");
334	            row.getChildren().add(actionLabel);
335	        }
336	        row.setAlignment(Pos.CENTER_LEFT);
337	        row.setPadding(new Insets(8, 0, 10, 0));
338	        return row;
339	    }
340	}
